settings.custom_liquid:
{%- assign now_ts       = 'now' | date: '%s' | plus: 0 -%}
{%- assign day          = 86400 -%}
{%- assign prep_start_ts  = now_ts | plus: day -%}
{%- assign prep_end_ts    = now_ts | plus: day | plus: day -%}
{%- assign deliv_start_ts = now_ts | plus: 518400 -%}
{%- assign deliv_end_ts   = now_ts | plus: 1209600 -%}
{%- assign order_date  = now_ts         | date: '%d %b' -%}
{%- assign prep_start  = prep_start_ts  | date: '%d %b' -%}
{%- assign prep_end    = prep_end_ts    | date: '%d %b' -%}
{%- assign deliv_start = deliv_start_ts | date: '%d %b' -%}
{%- assign deliv_end   = deliv_end_ts   | date: '%d %b' -%}

<div class="htl">

  <div class="htl__track" aria-hidden="true">
    <div class="htl__progress"></div>
  </div>

  <div class="htl__step htl__step--done">
    <div class="htl__dot">
      <svg viewBox="0 0 16 16" fill="currentColor">
        <path fill-rule="evenodd" d="M10.5 3.5a2.5 2.5 0 0 0-5 0V4h5zm1 0V4H15v10a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V4h3.5v-.5a3.5 3.5 0 1 1 7 0m-.646 5.354a.5.5 0 0 0-.708-.708L7.5 10.793 6.354 9.646a.5.5 0 1 0-.708.708l1.5 1.5a.5.5 0 0 0 .708 0z"/>
      </svg>
    </div>
    <div class="htl__date">{{ order_date }}</div>
    <div class="htl__label">Commande</div>
  </div>

  <div class="htl__step htl__step--done">
    <div class="htl__dot">
      <svg viewBox="0 0 16 16" fill="currentColor">
        <path d="M0 3.5A1.5 1.5 0 0 1 1.5 2h9A1.5 1.5 0 0 1 12 3.5V5h1.02a1.5 1.5 0 0 1 1.17.563l1.481 1.85a1.5 1.5 0 0 1 .329.938V10.5a1.5 1.5 0 0 1-1.5 1.5H14a2 2 0 1 1-4 0H5a2 2 0 1 1-3.998-.085A1.5 1.5 0 0 1 0 10.5zm1.294 7.456A2 2 0 0 1 4.732 11h5.536a2 2 0 0 1 .732-.732V3.5a.5.5 0 0 0-.5-.5h-9a.5.5 0 0 0-.5.5v7a.5.5 0 0 0 .294.456M12 10a2 2 0 0 1 1.732 1h.768a.5.5 0 0 0 .5-.5V8.35a.5.5 0 0 0-.11-.312l-1.48-1.85A.5.5 0 0 0 13.02 6H12zm-9 1a1 1 0 1 0 0 2 1 1 0 0 0 0-2m9 0a1 1 0 1 0 0 2 1 1 0 0 0 0-2"/>
      </svg>
    </div>
    <div class="htl__date">{{ prep_start }} – {{ prep_end }}</div>
    <div class="htl__label">En préparation</div>
  </div>

  <div class="htl__step htl__step--done">
    <div class="htl__dot">
      <svg viewBox="0 0 16 16" fill="currentColor">
        <path d="M3 2.5a2.5 2.5 0 0 1 5 0 2.5 2.5 0 0 1 5 0v.006c0 .07 0 .27-.038.494H15a1 1 0 0 1 1 1v1a1 1 0 0 1-1 1H1a1 1 0 0 1-1-1V4a1 1 0 0 1 1-1h2.038A3 3 0 0 1 3 2.506zm1.068.5H7v-.5a1.5 1.5 0 1 0-3 0c0 .085.002.274.045.43zM9 3h2.932l.023-.07c.043-.156.045-.345.045-.43a1.5 1.5 0 0 0-3 0zm6 4v7.5a1.5 1.5 0 0 1-1.5 1.5H9V7zM2.5 16A1.5 1.5 0 0 1 1 14.5V7h6v9z"/>
      </svg>
    </div>
    <div class="htl__date">{{ deliv_start }} – {{ deliv_end }}</div>
    <div class="htl__label">Livraison estimée</div>
  </div>

</div>

<style>
  .htl {
    position: relative;
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    text-align: center;
    margin-top: 16px;
    padding-bottom: 4px;
    isolation: isolate;
  }

  .htl__track {
    position: absolute;
    top: 19px;
    left: 16%;
    right: 16%;
    height: 3px;
    background: #B88B59;
    border-radius: 99px;
    z-index: 0;
    overflow: hidden;
  }

  .htl__progress {
    width: 100%;
    height: 100%;
    background: #B88B59;
    border-radius: 99px;
  }

  .htl__step {
    position: relative;
    z-index: 2;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 7px;
  }

  .htl__dot {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .htl__dot svg { width: 16px; height: 16px; }

  .htl__step--done .htl__dot {
    background: #B88B59;
    color: #fff;
    box-shadow: 0 2px 8px rgba(74,127,167,0.30);
  }
  .htl__step--pending .htl__dot {
    background: #F0F4F7;
    color: #9aafc0;
    border: 2px solid #E6ECF1;
  }

  .htl__date {
    font-weight: 700;
    font-size: 13px;
    color: #2F3A44;
    line-height: 1.2;
  }
  .htl__step--pending .htl__date { color: #9aafc0; }

  .htl__label {
    font-size: 11.5px;
    color: #6b7280;
    line-height: 1.2;
  }

  @media (max-width: 600px) {
    .htl__dot { width: 34px; height: 34px; }
    .htl__dot svg { width: 14px; height: 14px; }
    .htl__track { top: 16px; }
    .htl__date  { font-size: 11px; }
    .htl__label { font-size: 10.5px; }
  }
</style>
